// Get the markdown content from the previous node
const markdown = $input.first().json.data.markdown;

let cleanedMarkdown = markdown
  // Remove app banners and promotional content
  .replace(/!\[.*?app.*?logo.*?\]\(.*?\)/gi, '')
  .replace(/^.*?(?:Use the app|Find great deals|Open|Download).*?$/gmi, '')

  // Remove image galleries (repeated image markdown patterns)
  .replace(/(?:\*\s+!\[.*?\]\(https?:\/\/.*?\)\s*\n){3,}/gi, '')
  .replace(/\d+\s*\/\s*\d+\s*\n/gi, '')  // Remove image counters like "1 / 8"

  // Remove header/navigation patterns
  .replace(/^.*?(?:Sign In|Register|Post Ad|My Kijiji|Messages|Menu|Search|Categories|Browse).*?$/gmi, '')
  .replace(/\[.*?\]\(\#header.*?\)/gi, '')

  // Remove map-related content
  .replace(/!\[\]\(https?:\/\/maps\.googleapis\.com\/.*?\)/gi, '')
  .replace(/!\[\]\(data:image\/svg\+xml.*?\)/gi, '')
  .replace(/^.*?(?:Map Data|Keyboard shortcuts|Click to toggle|Open this area in|Report a map error).*?$/gmi, '')
  .replace(/^\|[\s\|\-]+\|$/gm, '')  // Remove table borders
  .replace(/^\|\s*(?:←|→|↑|↓|\+|\-|Home|End|Page Up|Page Down).*?\|$/gmi, '')  // Remove keyboard shortcut tables
  .replace(/Map\s*\n\s*\*\s+Terrain\s*\n\s*Satellite/gi, '')
  .replace(/\d+\s*m\s*\n/gi, '')  // Remove distance markers like "200 m"

  // Remove Google/Bing tracking pixels and analytics
  .replace(/!\[\]\(https?:\/\/bat\.bing\.net\/.*?\)/gi, '')
  .replace(/!\[\]\(https?:\/\/.*?analytics.*?\)/gi, '')

  // Remove "Similar listings" sections
  .replace(/Similar listings[\s\S]*?$/gi, '')

  // Remove footer patterns
  .replace(/^.*?(?:About Kijiji|Careers|Advertise|Help|Terms of Use|Privacy Policy|Safety Tips).*?$/gmi, '')
  .replace(/^.*?(?:Copyright|All rights reserved|©|Report Listing).*?$/gmi, '')
  .replace(/\[.*?\]\((?:https?:)?\/\/(?:help|www\.google\.com\/intl|www\.google\.com\/maps).*?\)/gi, '')

  // Remove "Listed By" and contact sections (optional - comment out if needed)
  .replace(/Listed By[\s\S]*?(?=\n#{1,3}\s|\n\*\*|$)/gi, '')
  .replace(/Request a viewing[\s\S]*?(?=\n#{1,3}\s|\n\*\*|$)/gi, '')

  // Remove social sharing and action buttons
  .replace(/^.*?(?:Save|Share|Reveal phone|View all listings|Send message).*?$/gmi, '')

  // Remove "Explore the area" and walk/transit scores (optional - comment out if needed)
  .replace(/Explore the area[\s\S]*?(?:Walk score|Transit score|Bike score)[\s\S]*?(?=\n#{1,3}\s|\n\*\*|$)/gi, '')

  // Remove empty markdown links and images
  .replace(/!\[\]\(\)/gi, '')
  .replace(/\[\]\(\)/gi, '')

  // Clean up multiple consecutive blank lines
  .replace(/\n{3,}/g, '\n\n')

  // Remove lines that are just whitespace
  .replace(/^\s+$/gm, '')

  // Trim whitespace from start and end
  .trim();

// Return the cleaned markdown
return {
  json: {
    cleanedMarkdown: cleanedMarkdown,
    originalMarkdown: markdown,
    charactersRemoved: markdown.length - cleanedMarkdown.length
  }
};

